
INSERT INTO threats (category, title, description, red_flags, target_audience, severity, examples) VALUES
-- ELDERLY threats
('smishing', 'Мошенничество с доставкой', 'Поддельное SMS о посылке с требованием оплатить "таможенный сбор" или перейти по ссылке для отслеживания.', ARRAY['Неожиданная посылка','Ссылка для оплаты','Срочность'], ARRAY['elderly'], 'high', ARRAY['«Ваша посылка задержана на таможне. Оплатите 299₽: bit.ly/track-parcel»','«СДЭК: для получения посылки подтвердите данные»']),
('scam', 'Лотерея и выигрыш', 'Сообщение о крупном выигрыше в лотерею с требованием "оплатить налог" для получения приза.', ARRAY['Неожиданный выигрыш','Оплата для получения','Давление'], ARRAY['elderly'], 'critical', ARRAY['«Поздравляем! Вы выиграли 500 000₽! Для получения оплатите налог 5%»','«Ваш номер выбран в акции Сбера. Переведите 2000₽ для активации»']),
('vishing', 'Техподдержка Microsoft/Apple', 'Звонок или всплывающее окно от "техподдержки" с сообщением о вирусе и требованием установить программу удалённого доступа.', ARRAY['Паника из-за вируса','Удалённый доступ','Оплата за ремонт'], ARRAY['elderly','professional'], 'critical', ARRAY['«Ваш компьютер заражён! Установите TeamViewer для исправления»','«Звонок из Microsoft: обнаружена угроза безопасности»']),
('phishing', 'Фишинг через мессенджеры', 'Сообщение в WhatsApp/Telegram от "друга" с просьбой проголосовать или перейти по ссылке.', ARRAY['Ссылка от знакомого','Просьба проголосовать','Взломанный аккаунт'], ARRAY['elderly','child'], 'high', ARRAY['«Привет! Проголосуй за мою племянницу: contest-vote.ru»','«Это ты на фото? Посмотри: photo-check.xyz»']),
('romance', 'Романтическое мошенничество', 'Знакомство на сайте знакомств, быстрое "влюбление" и просьба о деньгах на билет/лечение.', ARRAY['Быстрые чувства','Просьба о деньгах','Нежелание встретиться'], ARRAY['elderly'], 'critical', ARRAY['«Дорогая, мне нужны деньги на билет к тебе»','«У меня проблемы с банком, переведи на этот счёт»']),

-- CHILD threats
('grooming', 'Маскировка под сверстника', 'Взрослый выдаёт себя за ровесника в играх или соцсетях, выманивает личную информацию и фото.', ARRAY['Слишком много вопросов','Просьба о фото','Секреты от родителей'], ARRAY['child'], 'critical', ARRAY['«Давай дружить! Пришли своё фото, только родителям не говори»','«Ты мне нравишься, расскажи где живёшь»']),
('malware', 'Вирус через моды для игр', 'Предложение скачать "бесплатные моды" или "читы" для игр с вредоносным ПО внутри.', ARRAY['Бесплатные читы','Скачивание файлов','Неофициальный сайт'], ARRAY['child'], 'high', ARRAY['«Скачай бесплатные читы для Minecraft: free-mods.xyz»','«Установи этот мод и получи суперсилу в игре!»']),
('cyberbullying', 'Кибербуллинг и шантаж', 'Угрозы распространить личную информацию или фото, если жертва не выполнит требования.', ARRAY['Угрозы','Шантаж','Требование денег'], ARRAY['child'], 'critical', ARRAY['«Если не пришлёшь деньги, я выложу твоё фото»','«Я знаю где ты учишься, делай что говорю»']),
('scareware', 'Фейковый антивирус', 'Всплывающее окно "Ваш телефон заражён!" с требованием скачать "антивирус", который является вирусом.', ARRAY['Пугающее предупреждение','Скачивание приложения','Поддельный сайт'], ARRAY['child','elderly'], 'high', ARRAY['«ВНИМАНИЕ: обнаружено 13 вирусов! Скачайте антивирус СЕЙЧАС»','«Ваш телефон взломан! Нажмите для защиты»']),
('impersonation', 'Подмена аккаунта друга', 'Взломанный или поддельный аккаунт друга просит срочно перевести деньги или сообщить код.', ARRAY['Срочная просьба','Запрос кода','Необычное поведение'], ARRAY['child','elderly'], 'high', ARRAY['«Привет, срочно скинь 500₽ на карту, потом отдам!»','«Пришли код из СМС, мне нужно для входа»']);
